#!/usr/bin/env node

import fs from "node:fs";
import path from "node:path";

const ROOT = process.cwd();
const MANIFEST_PATH = path.join(ROOT, "scripts/local-speech/models-manifest.json");
const OUT_DIR = path.join(ROOT, ".local-speech");

function readJson(filePath) {
  return JSON.parse(fs.readFileSync(filePath, "utf8"));
}

function ensureDir(dirPath) {
  fs.mkdirSync(dirPath, { recursive: true });
}

function buildEnvTemplate(manifest) {
  const lines = [
    "# Generated by npm run speech:bootstrap",
    "# Copy the lines you want into .env.local, then start the matching local services.",
    ""
  ];

  manifest.services.forEach((service) => {
    lines.push(`# ${service.label}`);
    Object.entries(service.env).forEach(([key, value]) => {
      lines.push(`${key}=${value}`);
    });
    lines.push("");
  });

  return lines.join("\n");
}

function buildStartChecklist(manifest) {
  const lines = [
    "# Local Speech Startup Checklist",
    "",
    "This file is generated and intentionally kept outside source control.",
    "",
    "## Model Directory",
    "",
    `- ${manifest.modelsDir}/`,
    "",
    "## Services"
  ];

  manifest.services.forEach((service) => {
    lines.push("");
    lines.push(`### ${service.label}`);
    lines.push("");
    lines.push(`- Provider: ${service.provider}`);
    lines.push(`- Expected service: ${service.startCommand}`);

    if (service.modelFiles.length > 0) {
      lines.push("- Optional model files:");
      service.modelFiles.forEach((file) => {
        lines.push(`  - ${file.relativePath}`);
        lines.push(`    Source: ${file.source}`);
      });
    } else {
      lines.push("- No model file is managed by this repo for this service.");
    }
  });

  lines.push("");
  lines.push("## Verify");
  lines.push("");
  lines.push("```bash");
  lines.push("npm run speech:check -- --strict-practice");
  lines.push("```");

  return lines.join("\n");
}

function writeIfMissing(filePath, content) {
  if (fs.existsSync(filePath)) {
    return false;
  }

  fs.writeFileSync(filePath, content, "utf8");
  return true;
}

function createReport(manifest) {
  ensureDir(OUT_DIR);
  ensureDir(path.join(ROOT, manifest.modelsDir));

  manifest.services.forEach((service) => {
    service.modelFiles.forEach((file) => {
      ensureDir(path.dirname(path.join(ROOT, manifest.modelsDir, file.relativePath)));
    });
  });

  const envTemplatePath = path.join(OUT_DIR, "env.local.speech.example");
  const checklistPath = path.join(OUT_DIR, "START_LOCAL_SPEECH.md");
  const wroteEnvTemplate = writeIfMissing(envTemplatePath, buildEnvTemplate(manifest));
  const wroteChecklist = writeIfMissing(checklistPath, buildStartChecklist(manifest));

  return {
    ok: true,
    modelsDir: manifest.modelsDir,
    generatedDir: path.relative(ROOT, OUT_DIR),
    files: [
      {
        path: path.relative(ROOT, envTemplatePath),
        created: wroteEnvTemplate
      },
      {
        path: path.relative(ROOT, checklistPath),
        created: wroteChecklist
      }
    ],
    services: manifest.services.map((service) => ({
      id: service.id,
      label: service.label,
      startCommand: service.startCommand
    }))
  };
}

function printReport(report) {
  console.log("Learn English local speech bootstrap");
  console.log("");
  console.log(`Model directory: ${report.modelsDir}`);
  console.log(`Generated directory: ${report.generatedDir}`);
  console.log("");
  report.files.forEach((file) => {
    console.log(`${file.created ? "created" : "exists"} ${file.path}`);
  });
  console.log("");
  console.log("Services to start:");
  report.services.forEach((service) => {
    console.log(`- ${service.label}: ${service.startCommand}`);
  });
}

const args = new Set(process.argv.slice(2));
const manifest = readJson(MANIFEST_PATH);
const report = createReport(manifest);

if (args.has("--json")) {
  console.log(JSON.stringify(report, null, 2));
} else {
  printReport(report);
}
